/**
 * FIXME bad name, JUnit5Executor/JUnit5Launcher[InMPS] might be better
 */
public class ScriptJUnit5Launcher extends AbstractJUnit5Launcher {

  protected final Environment myEnvironment;

  private final WorkerCallback myWorkerCallback;
  private final JUnit5TestContributor myTestSupplier;
  private final File myTestProjectDir;

  private File myOutputDir;
  private boolean myIsOpenTestReport = false;
  private boolean myNeedTeamCityReport = false;

  /**
   * 
   * @param environment not null. need Environment here, not mps.Platform, to pass it down to EnvironmentAware tests
   * @param testData not null, tells which tests to run (or which modules to search for auto-discovery)
   * @param callback nt null, feedback mechanism
   * @param projectDir optional path to test project (the one tests would open, when/if necessary)
   */
  public ScriptJUnit5Launcher(Environment environment, TestData testData, WorkerCallback callback, File projectDir) {
    this(environment, new TestDiscoveryContributor(environment.getPlatform(), testData, callback), callback, projectDir);
  }

  public ScriptJUnit5Launcher(Environment environment, JUnit5TestContributor testData, WorkerCallback callback, File projectDir) {
    myEnvironment = environment;
    myWorkerCallback = callback;
    myTestSupplier = testData;
    myTestProjectDir = projectDir;
  }

  public void opentestReport(File outputDir) {
    myOutputDir = outputDir;
    myIsOpenTestReport = true;
  }

  public void legacyXmlReport(File outputDir) {
    myOutputDir = outputDir;
    myIsOpenTestReport = false;
  }

  public void teamcityReport() {
    myNeedTeamCityReport = true;
  }

  @Override
  public int launchTests() {
    FailureDetector failureDetector = new FailureDetector();

    launchTestsWithSession(collectTestClasses(), failureDetector);

    if (failureDetector.hasFailures()) {
      failureDetector.flushErrors(myWorkerCallback);
    }
    return failureDetector.failuresCount();
  }

  public void launchTests(TestExecutionListener listener) {
    launchTestsWithSession(collectTestClasses(), listener);
  }

  protected void launchTestsWithSession(List<DiscoverySelector> tests, TestExecutionListener executionListener) {
    TestSessionConfig sessionConfig = new TestSessionConfig();
    TestSession testSession = TestPlatform.getInstance().openSession(configureSession(sessionConfig));
    try {
      // this class is instantiated via ModuleClassCode which ensures proper MPS classloader for the code.
      ClassLoader contextCL = getClass().getClassLoader();
      launchTestsWithContextCL(contextCL, tests, executionListener);
    } finally {
      TestPlatform.getInstance().closeSession(testSession);
    }
  }

  protected TestSessionConfig configureSession(TestSessionConfig config) {
    config = config.withAccessory(Environment.class, myEnvironment);
    if (myTestProjectDir != null) {
      return config.withSystemProperty(SystemProperties.PROJECT_PATH, myTestProjectDir.getAbsolutePath());
    }
    return config;
  }

  @Override
  protected JUnit5TestExecutionListener createTestExecutionListener() {
    return new JUnit5TestExecutionListener() {
      @Override
      protected void flushSystemStreams() {
        // NOP: avoid attempting to flush stdout/stderr in order not to deadlock; MPS-37852
      }
    };
  }

  protected List<DiscoverySelector> collectTestClasses() {
    try {
      return myTestSupplier.collectSelectors();
    } catch (Exception ex) {
      myWorkerCallback.fatal("Failed to discover tests", ex);
      return Collections.emptyList();
    }
  }

  @Override
  protected File getTestReportsDir() {
    // FIXME replace these methods with generic getTestExecutionListeners():List, populated based on these values
    //      just need to figure out how to pass outputDir into session cfg params
    return myOutputDir;
  }

  @Override
  protected boolean isOpenTestReport() {
    return myIsOpenTestReport;
  }

  @Override
  protected boolean isRunningOnTeamCity() {
    return myNeedTeamCityReport;
  }

}
